import React, {Component} from 'react'
import Comment from '../comment'
import CommentForm from '../comment-form'
import toggleOpen from '../../decorators/toggleOpen'
import {connect} from 'react-redux'
import Loader from '../common/loader'
import {loadArticleComments} from '../../actions'
import {Consumer as AuthConsumer} from "../../contexts/auth";
import i18n from "../i18n"

class CommentList extends Component {
    static defaultProps = {
        comments: []
    }

    componentDidUpdate(prevProps, prevState, snapshot) {
        const {isOpen, article, loadArticleComments} = this.props
        if (
            isOpen &&
            !prevProps.isOpen &&
            !article.commentsLoading &&
            !article.commentsLoaded
        ) {
            loadArticleComments(article.id)
        }
    }

    render() {
        const {isOpen, toggleOpenItem, t} = this.props
        console.log('render CommentList')
        return (
            <div>
                <button onClick={toggleOpenItem}>
                    {isOpen ? t('hide comments') : 'show comments'}
                </button>
                <AuthConsumer>
                    {(contextValue) => <h5>{contextValue.contextUserName}</h5>}
                </AuthConsumer>
                {isOpen ? this.body : null}
            </div>
        )
    }

    get body() {
        const {
            article: {
                comments = [],
                id: articleId,
                commentsLoading,
                commentsLoaded
            },
            isOpen
        } = this.props

        if (!isOpen) return null;
        if (commentsLoading) return <Loader />
        if (!commentsLoaded) return null

        const body = comments.length ? (
            <ul>
                {comments.map(id => (
                    <li key={id}>
                        <Comment id={id} />
                    </li>
                ))}
            </ul>
        ) : (
            <h3>No comments yet</h3>
        )
        return <div>
            <CommentForm articleId={articleId} />
            {body}
        </div>
    }
}

export default connect(
    null,
    {loadArticleComments}
)(toggleOpen(i18n(CommentList)))
